using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // ───────── AddItem ─────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _sut.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(19.98m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _sut.AddItem("SKU-1", 1, 5.00m);
        _sut.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleSkus_SumsAll()
    {
        _sut.AddItem("A", 1, 10.00m);
        _sut.AddItem("B", 2, 5.00m);

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.AddItem(null!, 1, 1.00m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", qty, 1.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", 1, -1.00m));
    }

    // ───────── RemoveItem ─────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _sut.AddItem("A", 1, 10.00m);
        _sut.AddItem("B", 1, 5.00m);

        _sut.RemoveItem("A");

        Assert.AreEqual(5.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.RemoveItem(null!));
    }

    // ───────── CalculateTotal ─────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_ZeroPriceItem_ReturnsZero()
    {
        _sut.AddItem("FREE", 3, 0.00m);

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    // ───────── ApplyCoupon ─────────

    [TestMethod]
    [DataRow("SAVE10", 90.00, DisplayName = "10% off")]
    [DataRow("SAVE20", 80.00, DisplayName = "20% off")]
    [DataRow("HALF", 50.00, DisplayName = "50% off")]
    public void ApplyCoupon_ValidCode_ReducesTotal(string code, double expectedTotal)
    {
        _sut.AddItem("SKU-1", 1, 100.00m);

        _sut.ApplyCoupon(code);

        Assert.AreEqual((decimal)expectedTotal, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_AppliesDiscount()
    {
        _sut.AddItem("SKU-1", 1, 100.00m);

        _sut.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedByNewCoupon_UsesLatest()
    {
        _sut.AddItem("SKU-1", 1, 100.00m);
        _sut.ApplyCoupon("SAVE10");
        _sut.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _sut.CalculateTotal());
    }
}

